// Rate limiting check using in-memory window
// Note: For production, use external rate limiter (Redis, etc.)
// This stub provides structure for rate limiting logic

// n8n webhook puts POST body directly in $json (not $json.body)
const webhookData = $('Webhook').first().json;
const webhookBody = webhookData.body || webhookData; // Handle both formats
const clientIp = webhookData.headers?.['x-forwarded-for'] || 
                 webhookData.headers?.['x-real-ip'] || 
                 'unknown';

// Log rate limit check (actual enforcement at infrastructure level)
console.log(`Rate limit check for IP: ${clientIp}`);
console.log(`Webhook body keys: ${Object.keys(webhookBody).join(', ')}`);

// Pass through with rate limit metadata
return [{
  json: {
    ...webhookBody,
    _rateLimitMeta: {
      clientIp,
      timestamp: new Date().toISOString(),
      // In production, check against Redis/memory store
      allowed: true
    }
  }
}];

// Process thresholds config from fetched data
const thresholdsConfig = $input.first().json;
const webhookData = $('Rate Limit Check').first().json;

// Get rate limiting config
const rateLimiting = thresholdsConfig.rate_limiting || {};
const configInfo = {
  requestsPerMinute: rateLimiting.requests_per_minute || 10,
  requestsPerHour: rateLimiting.requests_per_hour || 100,
  globalPerMinute: rateLimiting.global_per_minute || 100
};

// Get intake thresholds for story queue decision
const intakeConfig = thresholdsConfig.intake || {};

console.log(`Loaded thresholds config: runtime.use_stubs=${thresholdsConfig.runtime?.use_stubs}`);
console.log(`Loaded intake thresholds: relevance=${intakeConfig.story_queue_relevance_threshold}, credibility=${intakeConfig.story_queue_credibility_threshold}`);
console.log(`Rate limiting config loaded: ${JSON.stringify(configInfo)}`);

return [{
  json: {
    ...thresholdsConfig,
    _webhookData: webhookData,
    _rateLimitConfig: configInfo
  }
}];

// Validate input with thresholds from config
// Now also captures story-specific and project-specific fields
const merged = $input.first().json;
const rateLimiting = merged._rateLimitConfig || {};
const webhookData = merged._webhookData;
const runtimeConfig = merged.runtime || { use_stubs: true };

// For stories/projects, description is the main content; for feedback, it's message
const messageContent = webhookData.description || webhookData.message || '';

if (!messageContent || messageContent.trim().length < 10) {
  throw new Error('Message/description required (min 10 chars)');
}

// Map submission type to valid database category
// DB constraint: 'tool-request', 'idea', 'report', 'question', 'collaboration', 'other'
const submissionType = webhookData.type || 'feedback';
let dbCategory = 'other';
if (submissionType === 'story') {
  dbCategory = 'report';  // Stories are reports of events/news
} else if (submissionType === 'project') {
  dbCategory = 'idea';    // Project proposals are ideas
} else if (webhookData.category) {
  // For feedback, map form categories to valid DB values
  const validCategories = ['tool-request', 'idea', 'report', 'question', 'collaboration', 'other'];
  dbCategory = validCategories.includes(webhookData.category) ? webhookData.category : 'other';
}

return [{
  json: {
    // Database columns (snake_case to match postgres)
    message: messageContent.trim(),
    contact: webhookData.contact || null,
    category: dbCategory,
    channel: 'web',
    submission_type: submissionType,
    title: webhookData.title || null,
    source_url: webhookData.sourceUrl || null,
    region: webhookData.region || null,
    urgency: webhookData.urgency || 'normal',

    // Project-specific fields (from form)
    problemStatement: webhookData.problemStatement || null,

    // Additional fields for workflow logic (not inserted to DB)
    safetyMode: webhookData.safetyMode || false,
    type: submissionType,
    sourceUrl: webhookData.sourceUrl || null,

    // Pass-through metadata
    _rateLimitConfig: rateLimiting,
    _runtime: runtimeConfig
  }
}];

// Prepare submission data for safe SQL insertion
// Escapes single quotes and prepares values
const input = $input.first().json;

function sqlEscape(val) {
  if (val === null || val === undefined) return 'NULL';
  if (typeof val === 'boolean') return val ? 'TRUE' : 'FALSE';
  if (typeof val === 'number') return String(val);
  // Escape single quotes by doubling them
  return "'" + String(val).replace(/'/g, "''") + "'";
}

const message = sqlEscape(input.message);
const contact = sqlEscape(input.contact);
const category = sqlEscape(input.category);
const channel = sqlEscape(input.channel || 'web');
const submission_type = sqlEscape(input.submission_type);
const title = sqlEscape(input.title);
const source_url = sqlEscape(input.source_url);
const region = sqlEscape(input.region);
const urgency = sqlEscape(input.urgency);

const query = `INSERT INTO submissions (message, contact, category, channel, submission_type, title, source_url, region, urgency)
VALUES (${message}, ${contact}, ${category}, ${channel}, ${submission_type}, ${title}, ${source_url}, ${region}, ${urgency})
RETURNING id, message`;

return [{
  json: {
    ...input,
    _insertQuery: query
  }
}];

// Prepare routing data for type-specific classification
// Removed redundant initial classification - type-specific classifiers handle this
const validateInput = $('Validate Input').first().json;
const submissionData = $('Insert Submission').first().json;

return [{
  json: {
    submissionId: submissionData.id,
    message: submissionData.message,
    category: validateInput.category,
    contact: validateInput.contact,
    _runtime: validateInput._runtime,
    _storyData: {
      type: validateInput.type,
      title: validateInput.title,
      sourceUrl: validateInput.sourceUrl,
      region: validateInput.region,
      urgency: validateInput.urgency,
      problemStatement: validateInput.problemStatement
    }
  }
}];

// Project Evaluate Stub for testing (1.13b)
// Provides keyword-based project assessment without calling Claude API

const parsedLLM = $('Prepare Routing Data').first().json;
const storyData = parsedLLM._storyData;
const message = parsedLLM.message;
const title = storyData?.title || '';
const problemStatement = storyData?.problemStatement || message;
const region = storyData?.region;
const urgency = storyData?.urgency || 'normal';

const fullText = (title + ' ' + problemStatement + ' ' + message).toLowerCase();

// Topic detection for tech stack suggestions
const topics = [];
if (fullText.includes('bitcoin') || fullText.includes('btc') || fullText.includes('lightning')) topics.push('bitcoin');
if (fullText.includes('zk') || fullText.includes('zero knowledge') || fullText.includes('proof')) topics.push('zk');
if (fullText.includes('mesh') || fullText.includes('p2p') || fullText.includes('peer')) topics.push('comms');
if (fullText.includes('privacy') || fullText.includes('encrypt') || fullText.includes('anonymous')) topics.push('privacy');
if (fullText.includes('identity') || fullText.includes('kyc') || fullText.includes('credential')) topics.push('identity');
if (fullText.includes('censor') || fullText.includes('blocked') || fullText.includes('firewall')) topics.push('censorship-resistance');
if (topics.length === 0) topics.push('sovereignty');

// Generate threat model based on content
let threat_model = 'Generic adversaries including network observers and platform operators.';
if (fullText.includes('government') || fullText.includes('state')) {
  threat_model = 'State-level adversaries with network monitoring capabilities, ability to compel platforms, and potential for targeted surveillance.';
} else if (fullText.includes('activist') || fullText.includes('journalist')) {
  threat_model = 'Adversaries targeting individuals including state actors, corporate surveillance, and social engineering attacks.';
}

// Identify affected groups
const affected_groups = ['Privacy-conscious users'];
if (fullText.includes('activist')) affected_groups.push('Activists in authoritarian regimes');
if (fullText.includes('journalist')) affected_groups.push('Journalists protecting sources');
if (fullText.includes('human rights')) affected_groups.push('Human rights organizations');
if (fullText.includes('developer')) affected_groups.push('Freedom tech developers');
if (affected_groups.length === 1) affected_groups.push('General users seeking privacy');

// Calculate feasibility score
let feasibility_score = 60;
if (fullText.includes('existing') || fullText.includes('integrate')) feasibility_score += 15;
if (fullText.includes('complex') || fullText.includes('research')) feasibility_score -= 15;
if (fullText.includes('simple') || fullText.includes('basic')) feasibility_score += 10;
feasibility_score = Math.max(30, Math.min(90, feasibility_score));

// Calculate impact score
let impact_score = 55;
if (fullText.includes('life') || fullText.includes('safety') || fullText.includes('threat')) impact_score += 25;
if (fullText.includes('many') || fullText.includes('widespread') || fullText.includes('global')) impact_score += 15;
if (fullText.includes('niche') || fullText.includes('specific')) impact_score -= 10;
impact_score = Math.max(30, Math.min(95, impact_score));

// Generate misuse risks
let misuse_risks = 'Could be used to coordinate harmful activities under cover of privacy. May enable evasion of legitimate law enforcement in non-authoritarian contexts.';
if (fullText.includes('anonymous')) {
  misuse_risks = 'Strong anonymity features could enable abuse, harassment, or illegal activities. Consider transparency options and abuse reporting mechanisms.';
}

// Suggest technical dependencies
const technical_dependencies = ['Cryptographic libraries (libsodium or equivalent)'];
if (topics.includes('bitcoin')) technical_dependencies.push('Bitcoin libraries (rust-bitcoin, bitcoinjs)');
if (topics.includes('comms')) technical_dependencies.push('Networking stack with P2P support');
if (topics.includes('zk')) technical_dependencies.push('ZK proving system (STARK, SNARK)');

// Suggest stack
const suggested_stack = ['Rust for core components', 'TypeScript for web interfaces'];
if (topics.includes('bitcoin')) suggested_stack.push('Bitcoin Core RPC or Electrum');
if (topics.includes('comms')) suggested_stack.push('libp2p for networking');

// Prior art
const prior_art = [];
if (topics.includes('bitcoin')) prior_art.push('Sparrow Wallet', 'Wasabi Wallet');
if (topics.includes('comms')) prior_art.push('Briar', 'Signal');
if (topics.includes('privacy')) prior_art.push('Tor Project', 'Tails');
if (prior_art.length === 0) prior_art.push('Review existing freedom tech projects');

// Open questions
const open_questions = [
  'What is the minimum viable UX for non-technical users?',
  'How to handle key management without trusted third parties?'
];
if (region) open_questions.push(`What are the specific requirements for ${region}?`);

// Check for spam
const is_spam = fullText.includes('guaranteed returns') || 
                fullText.includes('airdrop') || 
                fullText.includes('100x');

// Generate detected pattern
let detected_pattern = `Addresses ${topics.join('/')} needs for ${affected_groups[0].toLowerCase()}.`;
if (is_spam) detected_pattern = 'N/A - This is spam';

// Generate MVP scope
let mvp_scope = `CLI tool with core ${topics[0] || 'privacy'} functionality. Single-page documentation. Target: technical early adopters.`;
if (is_spam) mvp_scope = 'N/A - This is spam';

const result = {
  detected_pattern,
  threat_model: is_spam ? 'N/A - This is spam' : threat_model,
  affected_groups: is_spam ? [] : affected_groups,
  mvp_scope,
  misuse_risks: is_spam ? 'Submission flagged as spam.' : misuse_risks,
  feasibility_score: is_spam ? 0 : feasibility_score,
  impact_score: is_spam ? 0 : impact_score,
  technical_dependencies: is_spam ? [] : technical_dependencies,
  suggested_stack: is_spam ? [] : suggested_stack,
  prior_art: is_spam ? [] : prior_art,
  open_questions: is_spam ? [] : open_questions,
  reasoning: is_spam ? 'Spam patterns detected.' : `Stub evaluation: feasibility=${feasibility_score}, impact=${impact_score}, topics=${topics.join(', ')}`,
  priority: urgency,
  is_spam
};

return [{
  json: {
    content: [{ type: 'text', text: JSON.stringify(result) }],
    _submissionId: parsedLLM.submissionId,
    _message: message,
    _projectData: {
      title,
      problemStatement,
      description: message,
      region,
      urgency,
      topics
    },
    _runtime: parsedLLM._runtime
  }
}];

