// Wrap Claude API response for project evaluation
const claudeResponse = $input.first().json;
const parsedLLM = $('Prepare Routing Data').first().json;
const storyData = parsedLLM._storyData;

return [{
  json: {
    content: claudeResponse.content,
    _submissionId: parsedLLM.submissionId,
    _message: parsedLLM.message,
    _projectData: {
      title: storyData?.title || '',
      problemStatement: storyData?.problemStatement || parsedLLM.message,
      description: parsedLLM.message,
      region: storyData?.region,
      urgency: storyData?.urgency || 'normal'
    },
    _runtime: parsedLLM._runtime
  }
}];

// Handle errors from Project Evaluate Claude API call
const error = $input.first().json;
const parsedLLM = $('Prepare Routing Data').first().json;
const storyData = parsedLLM._storyData;

console.log('Project Evaluate Claude API error:', JSON.stringify(error));

const fallbackResult = {
  threat_model: 'Unable to assess - API error',
  affected_groups: ['Unknown - manual review required'],
  feasibility_score: 50,
  impact_score: 50,
  misuse_risks: 'Unable to assess - API error',
  technical_dependencies: [],
  suggested_stack: [],
  prior_art: [],
  open_questions: ['All aspects require manual review due to API error'],
  reasoning: 'Fallback evaluation due to API error - requires manual review',
  priority: 'normal',
  is_spam: false
};

return [{
  json: {
    content: [{ type: 'text', text: JSON.stringify(fallbackResult) }],
    _submissionId: parsedLLM.submissionId,
    _message: parsedLLM.message,
    _projectData: {
      title: storyData?.title || '',
      problemStatement: storyData?.problemStatement || parsedLLM.message,
      description: parsedLLM.message,
      region: storyData?.region,
      urgency: storyData?.urgency || 'normal'
    },
    _runtime: parsedLLM._runtime,
    _apiError: true
  }
}];

// Parse project evaluation LLM response
const input = $input.first().json;
let parsed;

try {
  let text = input.content[0].text;

  // Strip markdown code blocks if present
  text = text.trim();
  if (text.startsWith('```')) {
    text = text.replace(/^```(?:json)?\s*\n?/, '');
    text = text.replace(/\n?```\s*$/, '');
  }

  parsed = JSON.parse(text.trim());
} catch (e) {
  console.log('Parse Project LLM Response error:', e.message);
  parsed = {
    detected_pattern: 'Parse error - manual review required',
    threat_model: 'Parse error - manual review required',
    affected_groups: ['Unknown'],
    mvp_scope: 'Manual review required',
    feasibility_score: 50,
    impact_score: 50,
    misuse_risks: 'Parse error - manual review required',
    technical_dependencies: [],
    suggested_stack: [],
    prior_art: [],
    open_questions: ['All aspects require manual review'],
    reasoning: 'Failed to parse: ' + e.message,
    priority: 'normal',
    is_spam: false
  };
}

// Ensure all required fields with defaults
const result = {
  detected_pattern: parsed.detected_pattern || 'Not specified',
  threat_model: parsed.threat_model || 'Not specified',
  affected_groups: Array.isArray(parsed.affected_groups) ? parsed.affected_groups : ['General users'],
  mvp_scope: parsed.mvp_scope || 'MVP scope to be defined during triage',
  feasibility_score: parseInt(parsed.feasibility_score) || 50,
  impact_score: parseInt(parsed.impact_score) || 50,
  misuse_risks: parsed.misuse_risks || 'Not assessed',
  technical_dependencies: Array.isArray(parsed.technical_dependencies) ? parsed.technical_dependencies : [],
  suggested_stack: Array.isArray(parsed.suggested_stack) ? parsed.suggested_stack : [],
  prior_art: Array.isArray(parsed.prior_art) ? parsed.prior_art : [],
  open_questions: Array.isArray(parsed.open_questions) ? parsed.open_questions : [],
  reasoning: parsed.reasoning || '',
  priority: ['urgent', 'normal', 'low'].includes(parsed.priority) ? parsed.priority : 'normal',
  is_spam: Boolean(parsed.is_spam),

  // Pass through data
  _submissionId: input._submissionId,
  _message: input._message,
  _projectData: input._projectData,
  _runtime: input._runtime
};

return [{ json: result }];

// Handle spam project submission - mark as spam and skip processing
const data = $input.first().json;

console.log(`[SPAM] Project submission ${data._submissionId} flagged as spam. Skipping project idea creation.`);

return [{
  json: {
    success: true,
    type: 'project',
    submissionId: data._submissionId,
    projectIdeaId: null,
    githubIssueUrl: null,
    githubIssueCreated: false,
    isSpam: true,
    scores: {
      feasibility: data.feasibility_score || 0,
      impact: data.impact_score || 0
    },
    message: 'Submission flagged for review.'
  }
}];

// Build INSERT query for project_ideas table
const data = $input.first().json;
const projectData = data._projectData;

function escapeStr(str) {
  if (str === null || str === undefined) return 'NULL';
  return "'" + String(str).replace(/'/g, "''") + "'";
}

function formatPgArray(arr) {
  if (!arr || arr.length === 0) return "'{}'";
  const escaped = arr.map(s => '"' + String(s).replace(/"/g, '\\"').replace(/'/g, "''") + '"');
  return "'{" + escaped.join(',') + "}'";
}

// Use empty array for derived_from_insight_ids (community submission, not derived from insights)
// Link to submission via metadata instead
const query = `INSERT INTO project_ideas (
  derived_from_insight_ids,
  detected_pattern,
  problem_statement,
  threat_model,
  affected_groups,
  proposed_solution,
  mvp_scope,
  misuse_risks,
  feasibility_score,
  impact_score,
  technical_dependencies,
  suggested_stack,
  prior_art,
  open_questions,
  reasoning,
  priority,
  status
) VALUES (
  '{}',
  ${escapeStr(data.detected_pattern)},
  ${escapeStr(projectData.problemStatement)},
  ${escapeStr(data.threat_model)},
  ${formatPgArray(data.affected_groups)},
  ${escapeStr(projectData.description)},
  ${escapeStr(data.mvp_scope)},
  ${escapeStr(data.misuse_risks)},
  ${data.feasibility_score},
  ${data.impact_score},
  ${formatPgArray(data.technical_dependencies)},
  ${formatPgArray(data.suggested_stack)},
  ${formatPgArray(data.prior_art)},
  ${formatPgArray(data.open_questions)},
  ${escapeStr(data.reasoning)},
  ${escapeStr(data.priority)},
  'new'
) RETURNING id, feasibility_score, impact_score, priority, created_at`;

return [{
  json: {
    query,
    _projectIdeaData: {
      ...data,
      title: projectData.title,
      submissionId: data._submissionId
    }
  }
}];

// Prepare project idea for GitHub issue creation
const insertResult = $input.first().json;
const ideaData = $('Build Project Idea Query').first().json._projectIdeaData;

// Build issue title
let titleText = ideaData.title || ideaData._projectData?.problemStatement || '';
if (titleText.length > 60) {
  titleText = titleText.substring(0, 57).replace(/\s+\S*$/, '') + '...';
}
const issueTitle = `[Project Idea] ${titleText}`;

// Build issue body
const affectedGroupsList = (ideaData.affected_groups || []).map(g => `- ${g}`).join('\n') || '_Not specified_';
const dependenciesList = (ideaData.technical_dependencies || []).map(d => `- ${d}`).join('\n') || '_Not specified_';
const stackList = (ideaData.suggested_stack || []).map(s => `- ${s}`).join('\n') || '_Not specified_';
const priorArtList = (ideaData.prior_art || []).map(p => `- ${p}`).join('\n') || '_Not specified_';
const questionsList = (ideaData.open_questions || []).map(q => `- ${q}`).join('\n') || '_Not specified_';

// Get priority for labeling
const priority = insertResult.priority || ideaData.priority || 'normal';

const issueBody = `## Detected Pattern

${ideaData.detected_pattern || '_Not specified_'}

## Problem Statement

${ideaData._projectData?.problemStatement || ideaData._message}

## Proposed Solution

${ideaData._projectData?.description || ideaData._message}

## MVP Scope

${ideaData.mvp_scope || '_To be defined during triage_'}

## Threat Model

${ideaData.threat_model}

## Affected Groups

${affectedGroupsList}

## Misuse Risks

${ideaData.misuse_risks}

## Scores

- **Feasibility:** ${ideaData.feasibility_score}/100
- **Impact:** ${ideaData.impact_score}/100
- **Priority:** ${priority}

## Technical Dependencies

${dependenciesList}

## Suggested Stack

${stackList}

## Prior Art

${priorArtList}

## Open Questions

${questionsList}

## Evaluation Reasoning

${ideaData.reasoning || '_Not provided_'}

---
*Community-submitted project idea*
*Submission ID: \`${ideaData.submissionId}\`*
*Project Idea ID: \`${insertResult.id}\`*
*Auto-generated by Libertas Workflow C*`;

return [{
  json: {
    issueTitle,
    issueBody,
    projectIdeaId: insertResult.id,
    submissionId: ideaData.submissionId,
    feasibilityScore: insertResult.feasibility_score,
    impactScore: insertResult.impact_score,
    priority: priority,
    _runtime: ideaData._runtime
  }
}];

// STUB: Simulate GitHub issue creation for project ideas
const data = $input.first().json;

const stubIssueNumber = 200 + Math.floor(Math.random() * 800);
const stubIssueUrl = `https://github.com/FGUTech/libertas/issues/${stubIssueNumber}`;

// Build labels based on priority
const labels = ['project-idea', 'community-submitted'];
if (data.priority === 'urgent') labels.push('priority-urgent');
else if (data.priority === 'low') labels.push('priority-low');

console.log(`[STUB] Created mock GitHub issue #${stubIssueNumber} for project idea ${data.projectIdeaId} with priority ${data.priority}`);

return [{
  json: {
    html_url: stubIssueUrl,
    number: stubIssueNumber,
    title: data.issueTitle,
    state: 'open',
    labels: labels,
    _projectIdeaId: data.projectIdeaId,
    _submissionId: data.submissionId,
    _priority: data.priority,
    _isStub: true
  }
}];

// Wrap real GitHub API response for project issues
const githubResponse = $input.first().json;
const prepareData = $('Prepare Project for GitHub').first().json;

return [{
  json: {
    html_url: githubResponse.html_url,
    number: githubResponse.number,
    title: githubResponse.title,
    state: githubResponse.state,
    _projectIdeaId: prepareData.projectIdeaId,
    _submissionId: prepareData.submissionId,
    _isStub: false
  }
}];

// Handle errors from Project GitHub API call
const error = $input.first().json;
const prepareData = $('Prepare Project for GitHub').first().json;

console.log('Project GitHub API error:', JSON.stringify(error));

return [{
  json: {
    html_url: null,
    number: null,
    title: prepareData.issueTitle,
    state: 'error',
    _projectIdeaId: prepareData.projectIdeaId,
    _submissionId: prepareData.submissionId,
    _isStub: false,
    _apiError: true,
    _errorMessage: 'GitHub issue creation failed - will retry later'
  }
}];

// Build UPDATE queries for both project_ideas and submissions tables
const data = $input.first().json;

function escapeStr(str) {
  if (str === null || str === undefined) return 'NULL';
  return "'" + String(str).replace(/'/g, "''") + "'";
}

const issueUrl = data.html_url;

// Update project_ideas with GitHub issue URL
const updateIdeaQuery = `UPDATE project_ideas 
SET github_issue_url = ${escapeStr(issueUrl)},
    updated_at = NOW()
WHERE id = ${escapeStr(data._projectIdeaId)}::uuid
RETURNING id, github_issue_url`;

// Update submissions with GitHub issue URL and status
const updateSubmissionQuery = `UPDATE submissions
SET github_issue_url = ${escapeStr(issueUrl)},
    status = 'triaged'
WHERE id = ${escapeStr(data._submissionId)}::uuid`;

const combinedQuery = updateIdeaQuery + '; ' + updateSubmissionQuery;

console.log(`Updating project idea ${data._projectIdeaId} and submission ${data._submissionId} with GitHub issue URL: ${issueUrl || 'NULL'}`);

return [{
  json: {
    query: combinedQuery,
    _issueData: data
  }
}];

// Prepare response for project submissions
const updateResult = $input.first().json;
const issueData = $('Build Project Update Query').first().json._issueData;
const prepareData = $('Prepare Project for GitHub').first().json;

return [{
  json: {
    success: true,
    type: 'project',
    submissionId: issueData._submissionId,
    projectIdeaId: issueData._projectIdeaId,
    githubIssueUrl: issueData.html_url || null,
    githubIssueCreated: !!issueData.html_url,
    scores: {
      feasibility: prepareData.feasibilityScore,
      impact: prepareData.impactScore
    },
    priority: prepareData.priority,
    message: issueData.html_url 
      ? 'Your project idea has been recorded and a GitHub issue has been created for tracking.'
      : 'Your project idea has been recorded. GitHub issue creation failed - will be retried.'
  }
}];

// Extract text content from fetched HTML
// Provides source content for Claude to analyze alongside user's description

const parsedData = $('Prepare Routing Data').first().json;
const fetchResult = $input.first().json;

let extractedContent = '';
let fetchSuccess = true;

try {
  // Get the HTML content (could be string or in data field)
  const html = typeof fetchResult === 'string' ? fetchResult : 
               (fetchResult.data || fetchResult.body || JSON.stringify(fetchResult));

  if (typeof html === 'string' && html.length > 0) {
    // Basic HTML text extraction
    // Remove script and style tags and their content
    let text = html
      .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
      .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
      .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '')
      .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '')
      .replace(/<header[^>]*>[\s\S]*?<\/header>/gi, '');

    // Remove HTML tags but keep content
    text = text.replace(/<[^>]+>/g, ' ');

    // Decode HTML entities
    text = text
      .replace(/&nbsp;/g, ' ')
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'");

    // Clean up whitespace
    text = text.replace(/\s+/g, ' ').trim();

    // Truncate to reasonable size for LLM context
    extractedContent = text.substring(0, 8000);
    if (text.length > 8000) {
      extractedContent += '... [truncated]';
    }
  }
} catch (e) {
  console.log('Text extraction error:', e.message);
  fetchSuccess = false;
}

// Pass through all data with extracted content added
