const sourceUrl = storyData?.sourceUrl;
const region = storyData?.region;
const sourceContent = inputData._sourceContent?.extracted || '';

// Combine title, message, and source content for analysis
const fullText = (title + ' ' + message + ' ' + sourceContent).toLowerCase();

// Topic detection
const topics = [];
if (fullText.includes('bitcoin') || fullText.includes('btc') || fullText.includes('lightning')) topics.push('bitcoin');
if (fullText.includes('signal') || fullText.includes('mesh') || fullText.includes('briar') || fullText.includes('messaging')) topics.push('comms');
if (fullText.includes('vpn') || fullText.includes('tor') || fullText.includes('privacy') || fullText.includes('encrypt')) topics.push('privacy');
if (fullText.includes('censor') || fullText.includes('shutdown') || fullText.includes('blocked') || fullText.includes('ban')) topics.push('censorship-resistance');
if (fullText.includes('activist') || fullText.includes('protest') || fullText.includes('dissident') || fullText.includes('journalist')) topics.push('activism');
if (fullText.includes('surveillance') || fullText.includes('spy') || fullText.includes('monitor')) topics.push('surveillance');
if (fullText.includes('identity') || fullText.includes('passport') || fullText.includes('kyc')) topics.push('identity');
if (fullText.includes('payment') || fullText.includes('money') || fullText.includes('remittance')) topics.push('payments');
if (topics.length === 0) topics.push('sovereignty');

// Freedom relevance scoring
let freedom_relevance_score = 30;
if (topics.includes('censorship-resistance')) freedom_relevance_score += 25;
if (topics.includes('activism')) freedom_relevance_score += 20;
if (topics.includes('bitcoin') || topics.includes('comms')) freedom_relevance_score += 15;
if (fullText.includes('shutdown') || fullText.includes('repression')) freedom_relevance_score += 15;
if (fullText.includes('use') || fullText.includes('deployed') || fullText.includes('helped')) freedom_relevance_score += 10;
freedom_relevance_score = Math.min(freedom_relevance_score, 100);

// Credibility scoring
let credibility_score = 40;
if (sourceUrl && inputData._sourceContent?.fetchSuccess) {
  credibility_score = 60;
  if (sourceUrl.includes('reuters') || sourceUrl.includes('bbc') || sourceUrl.includes('aljazeera')) {
    credibility_score = 75;
  }
} else if (sourceUrl) {
  credibility_score = 55;
} else {
  credibility_score = Math.min(credibility_score + 15, 60);
}

// Extract geo
const geo = [];
if (region) geo.push(region);
const countries = ['Iran', 'China', 'Russia', 'Venezuela', 'Myanmar', 'Sudan', 'Nigeria', 'Uganda', 'Brazil', 'India'];
for (const country of countries) {
  if (fullText.includes(country.toLowerCase()) && !geo.includes(country)) {
    geo.push(country);
  }
}

