const safety_concern = (fullText.includes('name') && fullText.includes('activist')) ||
                       (fullText.includes('location') && fullText.includes('dissident')) ||
                       fullText.includes('address') ||
                       fullText.includes('phone number');

let risk_level = 'low';
if (fullText.includes('activist') || fullText.includes('dissident') || fullText.includes('journalist')) risk_level = 'medium';
if (safety_concern) risk_level = 'high';

