if (fullText.includes('emergency') || fullText.includes('ongoing')) priority = 'urgent';

const summary = (title || message.substring(0, 100)).substring(0, 200).replace(/\n/g, ' ').trim() + 
                (message.length > 100 && !title ? '...' : '');

