  safety_concern,
  reasoning: is_spam ? 'Spam patterns detected.' : `Stub: ${topics.length} topics, relevance=${freedom_relevance_score}, cred=${credibility_score}${sourceContent ? ' (source fetched)' : sourceUrl ? ' (source provided)' : ' (no source)'}`,
  risk_level: is_spam ? 'low' : risk_level,
  priority: is_spam ? 'low' : priority,
  summary: is_spam ? 'Spam - flagged for review' : summary,
  key_entities: [],
  is_spam
};

return [{
  json: {
    content: [{ type: 'text', text: JSON.stringify(result) }],
    _submissionId: inputData.submissionId,
    _message: message,
    _storyData: storyData,
    _sourceContent: inputData._sourceContent,
    _runtime: inputData._runtime
  }
