// Parse story classification LLM response
// Note: Queue decision is now made in workflow based on thresholds, not by LLM
const input = $input.first().json;
let parsed;

try {
  let text = input.content[0].text;

  // Strip markdown code blocks if present
  text = text.trim();
  if (text.startsWith('```')) {
    text = text.replace(/^```(?:json)?\s*\n?/, '');
    text = text.replace(/\n?```\s*$/, '');
  }

  parsed = JSON.parse(text.trim());
} catch (e) {
  console.log('Parse Story LLM Response error:', e.message);
  // Fallback
  parsed = {
    topics: ['needs-review'],
    freedom_relevance_score: 50,
    credibility_score: 30,
    geo: [],
    safety_concern: false,
    reasoning: 'Failed to parse: ' + e.message,
    risk_level: 'medium',
    priority: 'normal',
    summary: 'Parse error - manual review',
    key_entities: [],
    is_spam: false
  };
}

// Ensure all required fields with defaults
const result = {
  topics: Array.isArray(parsed.topics) ? parsed.topics : ['general'],
  freedom_relevance_score: parseInt(parsed.freedom_relevance_score) || 50,
  credibility_score: parseInt(parsed.credibility_score) || 30,
  geo: Array.isArray(parsed.geo) ? parsed.geo : [],
  safety_concern: Boolean(parsed.safety_concern),
  reasoning: parsed.reasoning || '',
  risk_level: parsed.risk_level || 'medium',
  priority: parsed.priority || 'normal',
  summary: (parsed.summary || '').substring(0, 200),
  key_entities: Array.isArray(parsed.key_entities) ? parsed.key_entities : [],
  is_spam: Boolean(parsed.is_spam),

  // Pass through data
  _submissionId: input._submissionId,
  _message: input._message,
  _storyData: input._storyData,
  _sourceContent: input._sourceContent,
  _runtime: input._runtime
};

return [{ json: result }];

// Restore story data after Postgres update and check queue threshold using config
// Queue decision is now based on thresholds from config, not LLM output

const postgresResult = $input.first().json;
const storyData = $('Parse Story LLM Response').first().json;

// Get thresholds from config (fetched at workflow start)
let intakeThresholds;
try {
  const configData = $('Merge Config & Agents').first().json;
  intakeThresholds = configData.intake || {};
} catch (e) {
  console.log('Could not get thresholds from config, using defaults');
  intakeThresholds = {};
}

// Get threshold values (with defaults matching old prompt logic)
const relevanceThreshold = intakeThresholds.story_queue_relevance_threshold || 80;
const credibilityThreshold = intakeThresholds.story_queue_credibility_threshold || 40;

// Check if story meets queue threshold
// Conditions: relevance >= threshold AND credibility >= threshold AND NOT safety_concern AND NOT spam
const meetsRelevance = storyData.freedom_relevance_score >= relevanceThreshold;
const meetsCredibility = storyData.credibility_score >= credibilityThreshold;
const noSafetyConcern = !storyData.safety_concern;
const notSpam = !storyData.is_spam;
const meetsQueueThreshold = meetsRelevance && meetsCredibility && noSafetyConcern && notSpam;

console.log(`Queue threshold check: relevance=${storyData.freedom_relevance_score}>=${relevanceThreshold}:${meetsRelevance}, credibility=${storyData.credibility_score}>=${credibilityThreshold}:${meetsCredibility}, safety_concern=${storyData.safety_concern}:${noSafetyConcern}, is_spam=${storyData.is_spam}:${notSpam}, result=${meetsQueueThreshold}`);

// Restore all story data with queue decision added
return [{
  json: {
    ...storyData,
    meetsQueueThreshold,
    _queueDecision: {
      relevanceThreshold,
      credibilityThreshold,
      meetsRelevance,
      meetsCredibility,
      noSafetyConcern,
      notSpam,
      result: meetsQueueThreshold
    }
  }
}];

// Handle spam story submission - skip processing
const data = $input.first().json;

console.log(`[SPAM] Story submission ${data._submissionId} flagged as spam. Skipping insight queue.`);

return [{
