      credibility: data.credibility_score || 0
    },
    message: 'Submission flagged for review.'
  }
}];

// Prepare data for user_story_items insert
// This table stores classified stories ready for Workflow A processing
const input = $input.first().json;

const url = input._storyData?.sourceUrl || 'intake://submission/' + input._submissionId;
const extractedText = input._message || '';
const sourceContent = input._sourceContent?.extracted || '';
const title = input._storyData?.title || input.summary || 'Untitled Story';
const region = input._storyData?.region || null;
const urgency = input._storyData?.urgency || 'normal';

// Compute content hash for deduplication
const crypto = require('crypto');
const contentHash = crypto.createHash('sha256').update(extractedText).digest('hex');

// Build metadata
const metadata = {
  submission_id: input._submissionId,
  source_content_length: sourceContent.length,
  classified_at: new Date().toISOString()
};

return [{
  json: {
    ...input,
    _userStoryData: {
      submissionId: input._submissionId,
      url,
      extractedText,
      contentHash,
      title,
      region,
      urgency,
      sourceContent,
      metadata: JSON.stringify(metadata),
      topics: JSON.stringify(input.topics),
      geo: JSON.stringify(input.geo),
      keyEntities: JSON.stringify(input.key_entities)
    }
  }
}];

// Build webhook response for queued story submissions
const prepareData = $('Prepare User Story Item').first().json;
const queueDecision = prepareData._queueDecision || {};

return [{
