    success: true,
    type: 'story',
    submissionId: prepareData._submissionId,
    queuedForPublishing: true,
    scores: {
      freedomRelevance: prepareData.freedom_relevance_score,
      credibility: prepareData.credibility_score
    },
    thresholds: {
      relevanceRequired: queueDecision.relevanceThreshold,
      credibilityRequired: queueDecision.credibilityThreshold
    },
    message: 'Your story has been queued for publishing review.'
  }
}];

// Build webhook response for stories that don't meet queue threshold
const data = $input.first().json;
const queueDecision = data._queueDecision || {};

// Determine why it wasn't queued
const reasons = [];
if (!queueDecision.meetsRelevance) {
  reasons.push(`Relevance score (${data.freedom_relevance_score}) below threshold (${queueDecision.relevanceThreshold})`);
}
if (!queueDecision.meetsCredibility) {
  reasons.push(`Credibility score (${data.credibility_score}) below threshold (${queueDecision.credibilityThreshold})`);
}
if (data.safety_concern) {
  reasons.push('Safety concern flagged - requires manual review');
}

return [{
  json: {
    success: true,
    type: 'story',
    submissionId: data._submissionId,
    queuedForPublishing: false,
    scores: {
      freedomRelevance: data.freedom_relevance_score,
      credibility: data.credibility_score
    },
    thresholds: {
      relevanceRequired: queueDecision.relevanceThreshold,
      credibilityRequired: queueDecision.credibilityThreshold
    },
    notQueuedReasons: reasons,
    message: 'Your story has been received but did not meet auto-publishing thresholds. It may still be reviewed manually.'
  }
}];

// Feedback Assess Stub for testing (1.13c)
// Provides keyword-based feedback assessment without calling Claude API

const parsedLLM = $('Prepare Routing Data').first().json;
const message = parsedLLM.message || '';
const category = parsedLLM.category || 'other';
const fullText = message.toLowerCase();

// Spam detection
const is_spam = fullText.includes('crypto airdrop') ||
                fullText.includes('click here') ||
                fullText.includes('guaranteed returns') ||
                fullText.includes('100x') ||
                (message.match(/https?:\/\//g) || []).length > 3;

// Priority assessment
let priority = 'normal';
if (fullText.includes('security') || fullText.includes('vulnerability') || fullText.includes('data loss')) {
  priority = 'urgent';
} else if (fullText.includes('urgent') || fullText.includes('emergency') || fullText.includes('broken')) {
  priority = 'urgent';
} else if (fullText.includes('minor') || fullText.includes('cosmetic') || fullText.includes('nice to have')) {
  priority = 'low';
}

// Extract actionable items
const actionable_items = [];
if (fullText.includes('bug') || fullText.includes('broken') || fullText.includes('not working')) {
  actionable_items.push('Investigate reported issue');
}
if (fullText.includes('feature') || fullText.includes('would be great') || fullText.includes('should')) {
  actionable_items.push('Evaluate feature request');
}
if (fullText.includes('content') || fullText.includes('article') || fullText.includes('cover')) {
  actionable_items.push('Review content suggestion');
}
if (actionable_items.length === 0) {
  actionable_items.push('Review feedback and determine next steps');
}

// Suggested assignee based on category
let suggested_assignee = 'triage';
if (category === 'bug') suggested_assignee = 'engineering';
else if (category === 'feature') suggested_assignee = 'engineering';
else if (category === 'content') suggested_assignee = 'content';

// Generate summary
const summary = message.substring(0, 180).replace(/\n/g, ' ').trim() + (message.length > 180 ? '...' : '');

// Sentiment detection
let sentiment = 'neutral';
if (fullText.includes('love') || fullText.includes('great') || fullText.includes('awesome')) sentiment = 'positive';
else if (fullText.includes('hate') || fullText.includes('terrible') || fullText.includes('awful')) sentiment = 'negative';
else if (fullText.includes('suggest') || fullText.includes('could') || fullText.includes('should')) sentiment = 'constructive';

const result = {
  is_spam,
  priority: is_spam ? 'low' : priority,
  actionable_items: is_spam ? [] : actionable_items,
  suggested_assignee: is_spam ? 'triage' : suggested_assignee,
  summary,
  sentiment,
  requires_clarification: message.length < 50 && !is_spam,
  clarification_needed: message.length < 50 && !is_spam ? 'More details would help us address your feedback' : ''
};

return [{
  json: {
    content: [{ type: 'text', text: JSON.stringify(result) }],
    _submissionId: parsedLLM.submissionId,
    _message: message,
    _feedbackData: {
      category: category,
      contact: parsedLLM.contact || null,
      requires_response: parsedLLM.requires_response || false
    },
    _runtime: parsedLLM._runtime
  }
}];

