  suggested_assignee: parsed.suggested_assignee || 'triage',
  summary: (parsed.summary || '').substring(0, 200),
  sentiment: parsed.sentiment || 'neutral',
  requires_clarification: Boolean(parsed.requires_clarification),
  clarification_needed: parsed.clarification_needed || '',

  // Pass through data
  _submissionId: input._submissionId,
  _message: input._message,
  _feedbackData: input._feedbackData,
  _runtime: input._runtime
};

return [{ json: result }];

