// Map feedback category to GitHub labels
// Category mapping per roadmap 1.13c:
// bug → [bug, feedback]
// feature → [enhancement, feedback]
// content → [content, feedback]
// other → [feedback, triage-needed]

const data = $input.first().json;
const feedbackData = data._feedbackData;
const category = feedbackData?.category || 'other';

let labels = ['feedback'];
let targetRepo = 'FGUTech/libertas'; // All feedback goes to main repo

switch (category) {
  case 'bug':
    labels = ['bug', 'feedback'];
    break;
  case 'feature':
    labels = ['enhancement', 'feedback'];
    break;
  case 'content':
    labels = ['content', 'feedback'];
    break;
  default:
    labels = ['feedback', 'triage-needed'];
}

// Add priority label if urgent
if (data.priority === 'urgent') {
  labels.push('priority-urgent');
}

// Build issue title
let titlePrefix = '[Feedback]';
if (category === 'bug') titlePrefix = '[Bug Report]';
else if (category === 'feature') titlePrefix = '[Feature Request]';
else if (category === 'content') titlePrefix = '[Content Suggestion]';

const titleText = data.summary.length > 50 
  ? data.summary.substring(0, 47).replace(/\s+\S*$/, '') + '...'
  : data.summary;

const issueTitle = `${titlePrefix} ${titleText}`;

// Build issue body
const actionableList = data.actionable_items.length > 0
  ? data.actionable_items.map(item => `- ${item}`).join('\n')
  : '_No specific actions identified_';

const contactSection = feedbackData.contact && feedbackData.requires_response
  ? '\n\n**Contact:** Provided (check submission record for details)\n**Response Requested:** Yes'
  : '';

const issueBody = `## Feedback

${data._message}

## Assessment

**Category:** ${category}
**Priority:** ${data.priority}
**Sentiment:** ${data.sentiment}
**Suggested Assignee:** ${data.suggested_assignee}

## Actionable Items

${actionableList}

${data.requires_clarification ? '### Clarification Needed\n\n' + data.clarification_needed + '\n\n' : ''}---
**Submission ID:** \`${data._submissionId}\`${contactSection}

---
*Auto-generated by Libertas Workflow C (Feedback Intake)*`;

return [{
  json: {
    issueTitle,
    issueBody,
    labels,
    targetRepo,
    ...data
  }
}];

